+    expected_json: String,
+    case_timeout: Duration,
+) -> TransformCaseReport {
+    TransformCaseReport {
+        case_id: case.case_id,
+        family: case.family,
+        mode: case.mode,
+        comparator: case.comparator,
+        drift_classification: DriftClassification::Timeout,
+        matched: false,
+        expected_json,
+        actual_json: None,
+        error: Some(format!(
+            "timeout waiting for case result after {}ms",
+            case_timeout.as_millis()
+        )),
+    }
